import Vue from 'vue'
import Vuex from 'vuex'

import layout from './modules/layoutManager'
import imageRetriever from './modules/imageRetriever'
import tagRetriever from './modules/tagRetriever'

import createLogger from 'vuex/dist/logger'

Vue.use(Vuex)
Vue.config.debug = false

// const debug = process.env.NODE_ENV !== 'production'
const debug = false

export default new Vuex.Store({
  modules: {
    layout,
    imageRetriever,
    tagRetriever  
  },
  state: {
    apiInfo : {
      baseDomain : 'http://203.150.55.236'
      ,baseSubPath: '/Reslice'
      ,serieUID: '1.2.764.0.1.3680043.2.1143.3993.20052262.3146.2662.911'
      ,user:'undefined'
      ,tagRequestPath: '/ImageInfo'
      ,imageHighQRequestPath:'/AccessImageHQ'
      ,imageLowQRequestPath:'/AccessImageLQ'      
    },
    appUiInfo : {
      toolboxHeight : 50
    },
    stateRecord: {}, //JUST Keep for undo,redo
    flagMode : ''
  },
  mutations : {
    SET_FLAG_MODE (state, payload) {
      console.log("payload.flagMode : "+ payload.flagMode)
      state.flagMode = payload.flagMode
      console.log("state.flagMode : "+ state.flagMode)
    }
  },
  getters: {
    getApiInfo(state){
      return state.apiInfo
    },   
    getAppUiInfo(state){
      return state.appUiInfo
    },
    getFlagMode(state){
      return state.flagMode
    }   
  },
  strict: debug,
  plugins: debug ? [createLogger()] : []
})



