<template>
  <section>
    <v-container>
      <v-row>
        <v-col cols="12">
          <canvas
            ref="drawLayer"
            v-on:mousedown="handleMouseDown"
            v-on:mouseup="handleMouseUp"
            v-on:mousemove="handleMouseMove"
            v-touch:tap="touchHandler"
            id="drawLayer"
          ></canvas>
        </v-col>
      </v-row>
    </v-container>
  </section>
</template>

<script>
// import store from '../../store/store.js'
// import {mapGetters} from 'vuex'
export default {
  props: ["canvasInfo"],
  data() {
    return {
      serieID: "AXIAL_HQ",

      tapTwice: 0,
      fontFix: 12,
      lineWidth: this.resizeComponentByScreen(1, 2),
      beginX: null,
      beginY: null,
      editState: false,
      pointBeenCreate: -1,
      pointBeenEdit: -1,
      mouseOverPoint: -1,
      // ,context2D_draw : drawLayer.getContext('2d')
      fontSpacing: 10,
      length_DataStructure: [],
      lengthId: 0,
      pickLengthID: -1,
      pcanvasDown: null
    };
  },
  methods: {
    configCanvasInfo: function() {
      var canv = this.$refs["drawLayer"];
      var ctx = canv.getContext("2d");
      let dcmTagInfo = this.$store.getters["tagRetriever/getTagInfo"];
      ctx.canvas.width = dcmTagInfo.image_width_resized;
      // console.log("image_width_resized : " + dcmTagInfo.image_width_resized)
      ctx.canvas.height = dcmTagInfo.image_height_resized;
      // console.log("image_height_resized : " + dcmTagInfo.image_height_resized)
      // ctx.fillStyle = this.canvasInfo.color
      // ctx.fillRect(0, 0, this.canvasInfo.width, this.canvasInfo.height)
      // console.log("this.Ready : " + this.Ready)
      // this.drawHighQImage()
    },
    handleMouseDown: function(ev) {
      if (this.isLengthMode()) {
        var mousePo = this.getMousePos(ev);
        // var eventX = (ev.pageX - ev.target.offsetLeft)
        // var eventY = (ev.pageY - ev.target.offsetTop)
        this.actionMouseMoveOfLength(mousePo.x, mousePo.y);

        if (this.actionMouseDownOfEditLength(mousePo.x, mousePo.y)) return;

        this.actionMouseDownOfCreateLength(mousePo.x, mousePo.y);
      }
    },
    handleMouseUp: function(ev) {
      var mousePo = this.getMousePos(ev)
      this.actionMouseUpOfLength(mousePo.x, mousePo.y)
    },
    getMousePos: function(evt) {
      var canvas = this.$refs["drawLayer"];
      var rect = canvas.getBoundingClientRect();
      return {
        x: evt.clientX - rect.left,
        y: evt.clientY - rect.top
      };
    },
    clearCanvas :function(){
      var canv = this.$refs['drawLayer']   
      var ctx = canv.getContext('2d')      
      ctx.clearRect(0, 0, canv.width, canv.height)
    },
    handleMouseMove: function(ev) {
      if (this.isLengthMode()) {
        // var mousePo = this.getMousePos(ev)
        // var eventX = mousePo.x//(ev.pageX - ev.target.offsetLeft)
        // var eventY = mousePo.y//(ev.pageY - ev.target.offsetTop)
        this.tapTwice = 0;
        var mousePo = this.getMousePos(ev);
        this.actionMouseMoveOfLength(mousePo.x, mousePo.y)
      }
    },
    isLengthMode: function() {
      if (this.$store.getters.getFlagMode == "LENGTH") {
        return true;
      }
    },
    actionMouseMoveOfLength: function(eventX, eventY) {
      console.log("this.pointBeenCreate : " + this.pointBeenCreate);
      if (this.pointBeenCreate === 0) {
        this.clearCanvas()

        var canv = this.$refs["drawLayer"]
        var context2D_draw = canv.getContext("2d")

        context2D_draw.beginPath()
        context2D_draw.lineWidth = this.resizeComponentByScreen(
          this.lineWidth,2)
        
        context2D_draw.moveTo(this.beginX, this.beginY)
        context2D_draw.lineTo(eventX, eventY)

        context2D_draw.strokeStyle = "#ff0000"
        context2D_draw.stroke();
        context2D_draw.closePath();

        // var reallength = this.findLength(actualP1, actualP2);

        var fontsize = 14;

        // fontsize = resizeComponentByScreen(15,2);

        context2D_draw.font = fontsize + "px sans-serif";
        context2D_draw.fillStyle = "#ff0000";
        // context2D_draw.fillText(reallength.toFixed(2) + " mm", actualP2.x+fontSpacing, actualP2.y+fontSpacing);

        // } else if (this.pointBeenEdit > -1) {  //Some point has been click to edit
        //     var actualP = context2D_draw.transformedPoint(eventX, eventY);
        //     var pcanvas = tranformWorldToCanvasPoint(actualP,imageLayer);

        //     var dx = pcanvas.x - pcanvasDown.x;//move - down
        //     var dy = pcanvas.y - pcanvasDown.y;
        //     pcanvasDown.x = pcanvas.x;//move
        //     pcanvasDown.y = pcanvas.y;

        //     switch (this.pointBeenEdit) {
        //         case 0:
        //             length_DataStructure[pickLengthID].p_startX = pcanvas.x;
        //             length_DataStructure[pickLengthID].p_startY = pcanvas.y;
        //             break;
        //         case 1:
        //             length_DataStructure[pickLengthID].p_endX = pcanvas.x;
        //             length_DataStructure[pickLengthID].p_endY = pcanvas.y;
        //             break;
        //         case 2:
        //             length_DataStructure[pickLengthID].p_startX += dx;// pcanvas.x;
        //             length_DataStructure[pickLengthID].p_startY += dy;// pcanvas.y;

        //             length_DataStructure[pickLengthID].p_endX += dx;//  pcanvas.x;
        //             length_DataStructure[pickLengthID].p_endY += dy;// pcanvas.y;
        //             break;
        //     }

        // } else if (this.pointBeenCreate === -1) {//State to find which point mouse is on

        //     detectLengthPoint(eventX, eventY);
      }
    },
    actionMouseDownOfCreateLength: function(eventX, eventY) {
      if (this.editState) return

      if (this.pointBeenCreate === -1) {
        /*First Point Click*/ this.beginX = eventX
        this.beginY = eventY
        this.pointBeenCreate = 0
      }
    },
    actionMouseUpOfLength: function(eventX, eventY) {
      if (this.pointBeenCreate === 0)/*Second Point Click*/ {
            this.pointBeenCreate = -1
            this.mouseOverPoint = -1
            if(this.beginX != this.eventX && this.beginY != this.eventY){

                var actualP1 = {x:this.beginX, y:this.beginY}//context2D_draw.transformedPoint(beginX, beginY)
                var actualP2 = {x:this.eventX, y:this.eventY}//context2D_draw.transformedPoint(eventX, eventY);
                this.commitToLengthDrawLayer(actualP1, actualP2);
            }
        }
        if (this.editState) {//Release Edit Point
            this.pointBeenEdit = -1
            this.editState = false
            return true; //Don't edit
        }
    },
    actionMouseDownOfEditLength: function(eventX, eventY) {
      if (
        this.mouseOverPoint === 0 ||
        this.mouseOverPoint === 1 ||
        this.mouseOverPoint === 2
      ) {
        //Start Edit Point

        var actualPStart = context2D_draw.transformedPoint(
          this.eventX,
          this.eventY
        );
        // pcanvasDown = tranformWorldToCanvasPoint(actualPStart,imageLayer);

        // this.pointBeenEdit = this.mouseOverPoint;
        // this.editState = true;
        // this.mouseOverPoint = -1; // reset mouse over point
        return true; //Don't edit
      }
      return false;
    },

    resizeComponentByScreen: function(inputVal, scale) {
      var touchDevice =
        navigator.maxTouchPoints || "ontouchstart" in document.documentElement;
      if (touchDevice) {
        return inputVal * scale;
      } else {
        return inputVal;
      }
    },
    set_Length_DataStructure: function(length_DataStructureRECRIVE) {
      this.length_DataStructure = length_DataStructureRECRIVE;
    },
    touchHandler: function() {
      console.log("touchHandler.....");
      if (this.isLengthMode()) {
        // var eventX = (ev.pageX - ev.target.offsetLeft);
        // var eventY = (ev.pageY - ev.target.offsetTop);
        // tapTwice ++;
        // if(tapTwice==2){
        //     if(lengthCore.actionMouseDownofDeleteLength(eventX, eventY)) return;
        //     tapTwice = 0;
        // }
      }
    },
    commitToLengthDrawLayer: function(actualP1, actualP2) {
        // var lengthValue = this.findLength(actualP1, actualP2);
        // // var pcanvasStart = tranformWorldToCanvasPoint(actualP1,imageLayer);
        // // var pcanvasEnd = tranformWorldToCanvasPoint(actualP2,imageLayer);

        // length_DataStructure.push({
        //     id: lengthId
        //     , p_startX: actualP1.x
        //     , p_startY: actualP1.y
        //     , p_endX: actualP2.x
        //     , p_endY: actualP2.y
        //     , length_value: lengthValue
        // });
        // appMain.getDrawLayerManager().drawAll();               
        //Draw Again..
        var canv = this.$refs["drawLayer"]
        var context2D_draw = canv.getContext("2d")

        context2D_draw.beginPath()
        context2D_draw.lineWidth = this.resizeComponentByScreen(
          this.lineWidth,2)
        
        context2D_draw.moveTo(actualP1.x, actualP1.y)
        context2D_draw.lineTo(actualP2.x, actualP2.y)

        context2D_draw.strokeStyle = "#ff0000"
        context2D_draw.stroke();
        context2D_draw.closePath();

    },



    findLength: function(p1, p2) {
      var length = Math.sqrt(
        (p1.x - p2.x) * (p1.x - p2.x) + (p1.y - p2.y) * (p1.y - p2.y)
      );
var reallength = length
      // var canvasW;
      // var imgW = IMAGE_LOCAL.IMAGE_WIDTH_RESIZED;

      // switch (CURRENT_VIEW_DISPLAY.WHAT_VIWE_SHOW) {
      //   case 1:
      //     if (imageLayer.id === "imageLayerAxial") {
      //       canvasW = IMAGE_SIZE_2D_CANVAS.AXIAL_W;
      //     } else if (imageLayer.id === "imageLayerCoronal") {
      //       canvasW = IMAGE_SIZE_2D_CANVAS.CORONAL_W;
      //     } else if (imageLayer.id === "imageLayerSagittal") {
      //       canvasW = IMAGE_SIZE_2D_CANVAS.SAGITTAL_W;
      //     }

      //     break;
      //   case 2:
      //     canvasW = IMAGE_SIZE_2D_CANVAS.SINGLE_VIEW_W;
      //     break;
      //   case 3:
      //     canvasW = IMAGE_SIZE_2D_CANVAS.MATRIX_VIEW_W;
      //     break;
      // }

      // var voxel = IMAGE_LOCAL.DATA_SPACING[0];

      // var scale = canvasW / imgW;
      // var reallength = voxel * (length / scale);

      return reallength;
    }
  },
  mounted() {
    console.log("COME MOUNT <Draw Canvas!>");
    this.configCanvasInfo();
    // this.drawHighQImage()
    // window.addEventListener('resize', this.handleResizeCanvas)
    // this.handleResizeCanvas();
  }
};
</script>

<style>
#drawLayer {
  position: absolute;
  left: 0%;
  top: 0%;
}
/* #staticLayerAxial {position: absolute;}#staticLayerCoronal {position: absolute;}
#staticLayerSagittal {position: absolute;}#imageLayerAxial {position: absolute;}
#drawLayerAxial {position: absolute;}#imageLayerCoronal {position: absolute;}
#drawLayerCoronal {position: absolute;}#imageLayerSagittal {position: absolute;}
#drawLayerSagittal {position: absolute;}#surfaceScreen {position: absolute;}
#staticLayerThreeD {position: absolute;} */
</style>


