<template>
  <div>    
    <v-progress-linear
      v-model="percentLoadDone"
      height="20"
    >
      <strong>{{ percentLoadDone + ' ' }} %</strong>
    </v-progress-linear>
  </div>
</template>

<script>
import store from '../../store/store.js'
  // import { mapGetters } from "vuex";
  export default {    
    data: () => ({
      serieID : 'AXIAL_HQ'
    }),
    // computed: mapGetters({
    //     serie: "imageRetriever/getSerieHQ"
    // }),    
    computed: {
      // serie: function () {  
      //   let serieMatch = this.$store.getters['imageRetriever/getSerieHQ'](this.serieID)                
      //   return serieMatch
      // },
      percentLoadDone () {
        let serieMatch = this.$store.getters['imageRetriever/getSerieHQByName'](this.serieID)        
        return Math.ceil((serieMatch.numLoadDone/serieMatch.numOfSlice) * 100)
      }
    }, 
    methods: {},
    mounted() {}   
  }
</script>


