<template>
  <v-container>
    <v-row>      
      <v-col cols="12">       
        <v-slider
          v-model="scrollIndex"
          min="0"
          max="255"
          label="Slice Index"
          thumb-label
        ></v-slider>        
      </v-col>
    </v-row>
  </v-container>
</template>

<script>
  export default {
    data () {
      return {        
        scrollIndex: 0,        
      }
    },
    computed: {                 
    },
    watch: {
      'scrollIndex': function(val, oldVal){            
        this.changeScrollBarValue(val)                    
      }
    },
    methods: {
      changeScrollBarValue :function(val){
        this.$store.dispatch('imageRetriever/adjustMentHQSliceIndex',{id:'AXIAL_HQ', sliceIndex:val})
      }
    }
  }
</script>


